#!/usr/bin/env node
const { spawnSync, execSync } = require('child_process')
const fs = require('fs')
const path = require('path')

try {
  process.env = require('../../env.json')
} catch {
  process.env = { PORT: '8080' }
}

const {
  BITCOIN_DATADIR,
  BITCOIN_RPCUSER,
  BITCOIN_RPCPASSWORD,
  BITCOIN_RPCPORT,
  BITCOIN_CLI_BIN
} = process.env

const BITCOIN_CLI = BITCOIN_CLI_BIN || '/usr/local/bin/bitcoin-cli'

const sleep = (ms) => new Promise(r => setTimeout(r, ms))

function run(cmd, opts = {}) {
  try {
    return execSync(cmd, { stdio: 'pipe', encoding: 'utf8', ...opts }).trim()
  } catch (e) {
    if (!opts.ignoreError) {
        console.error(`❌ Command failed: ${cmd}`)
        console.error(e.stderr?.toString() || e.message)
        throw e
    }
    return e.stderr?.toString() || e.message || ''
  }
}

async function waitForBitcoinRPC() {
  console.log('Waiting for RPC to be ready... (This can take a moment)');
  let attempts = 0;

  while (true) {
    const res = spawnSync(BITCOIN_CLI, [
      '-regtest',
      `-rpcuser=${BITCOIN_RPCUSER}`,
      `-rpcpassword=${BITCOIN_RPCPASSWORD}`,
      `-rpcport=${BITCOIN_RPCPORT}`,
      'getblockchaininfo'
    ]);

    if (res.status === 0) {
      console.log('RPC check successful.');
      break; 
    }

    await sleep(500);
    attempts++;

    if (attempts <= 5 || attempts % 20 === 0) {
      console.log(`RPC check attempt ${attempts} failed...`);
      if (res.stderr && res.stderr.toString()) {
        const errorMsg = res.stderr.toString().trim();
        console.error(`Error: ${errorMsg}`);
        if (errorMsg.includes("error code: -28")) {
            console.log("(This is normal, bitcoind is still warming up.)");
        }
      } else if (res.error) {
         console.error(`Spawn Error: ${res.error.message}`);
         if (res.error.code === 'ENOENT') {
            console.log(`(Could not find executable: ${BITCOIN_CLI}. Check your BITCOIN_CLI_BIN in env.json)`);
         }
      }
    }
  }
}

function setupWalletAndMine() {
  const WALLET = 'regtestwallet'
  console.log('Checking wallet status...')
  
  const wallets = run(
    `${BITCOIN_CLI} -regtest \
    -rpcuser="${BITCOIN_RPCUSER}" \
    -rpcpassword="${BITCOIN_RPCPASSWORD}" \
    -rpcport=${BITCOIN_RPCPORT} listwallets`,
    { ignoreError: true }
  )

  if (wallets.includes(`"${WALLET}"`)) {
    console.log(`Wallet '${WALLET}' is already loaded.`)
  } else {
    const walletDirs = run(
      `${BITCOIN_CLI} -regtest \
      -rpcuser="${BITCOIN_RPCUSER}" \
      -rpcpassword="${BITCOIN_RPCPASSWORD}" \
      -rpcport=${BITCOIN_RPCPORT} listwalletdir`,
      { ignoreError: true }
    )
    if (walletDirs.includes(`"${WALLET}"`)) {
      console.log('Wallet directory exists but not loaded — loading it...')
      run(
        `${BITCOIN_CLI} -regtest \
        -rpcuser="${BITCOIN_RPCUSER}" \
        -rpcpassword="${BITCOIN_RPCPASSWORD}" \
        -rpcport=${BITCOIN_RPCPORT} loadwallet "${WALLET}"`,
        { ignoreError: true }
      )
    } else {
      console.log(`Creating new wallet '${WALLET}'...`)
      run(
        `${BITCOIN_CLI} -regtest \
        -rpcuser="${BITCOIN_RPCUSER}" \
        -rpcpassword="${BITCOIN_RPCPASSWORD}" \
        -rpcport=${BITCOIN_RPCPORT} createwallet "${WALLET}"`,
        { ignoreError: true }
      )
    }
  }

  const newAddr = run(
    `${BITCOIN_CLI} -regtest \
    -rpcuser="${BITCOIN_RPCUSER}" \
    -rpcpassword="${BITCOIN_RPCPASSWORD}" \
    -rpcport=${BITCOIN_RPCPORT} \
    -rpcwallet="${WALLET}" getnewaddress`
  )
  console.log(`Mining 101 blocks to ${newAddr} ...`)
  run(
    `${BITCOIN_CLI} -regtest \
    -rpcuser="${BITCOIN_RPCUSER}" \
    -rpcpassword="${BITCOIN_RPCPASSWORD}" \
    -rpcport=${BITCOIN_RPCPORT} \
    -rpcwallet="${WALLET}" generatetoaddress 101 "${newAddr}"`,
    { ignoreError: true }
  )
  console.log('✅ Wallet ready and blocks mined.')
}


module.exports = {
  async start() {
    console.log('=== Starting Bitcoin Regtest ===')
    if (!fs.existsSync(BITCOIN_DATADIR)) {
      console.log(`⚠️ Creating Bitcoin data dir: ${BITCOIN_DATADIR}`)
      fs.mkdirSync(BITCOIN_DATADIR, { recursive: true })
    }
    const running = spawnSync('pgrep', ['-x', 'bitcoind'])
    if (running.status !== 0) {
      run(
        `bitcoind -regtest -daemon \
        -datadir="${BITCOIN_DATADIR}" \
        -rpcuser="${BITCOIN_RPCUSER}" \
        -rpcpassword="${BITCOIN_RPCPASSWORD}" \
        -rpcallowip=127.0.0.1 \
        -rpcport=${BITCOIN_RPCPORT} \
        -fallbackfee=0.0002`
      )
    }
    console.log('✅ bitcoind launched, waiting for readiness...')
    await waitForBitcoinRPC()
    console.log('✅ bitcoind RPC ready.')

    setupWalletAndMine()

    console.log('✅ bitcoind is fully set up and ready.')
  },

  async stop() {
    console.log('Stopping bitcoind...')
    try {
      run(
        `${BITCOIN_CLI} -regtest \
        -rpcuser="${BITCOIN_RPCUSER}" \
        -rpcpassword="${BITCOIN_RPCPASSWORD}" \
        -rpcport=${BITCOIN_RPCPORT} stop`,
        { ignoreError: true }
      )
      console.log('🛑 bitcoind stop requested.')
    } catch {
      console.log('⚠️ bitcoind may not be running.')
    }
  }
}